class Solution {
    public int distinctSequences(int n) {
        int MOD = 1000000007;
        int[] dp = new int[n + 1];
        int[] count = new int[6];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            dp[i] = 0;
            for (int j = 1; j <= 6; j++) {
                if (i - 3 >= 0 && count[j] > 0) {
                    dp[i] = (dp[i] + dp[i - 3]) % MOD;
                }
                if (i - 1 >= 0 && j != 1 && j != 2 && j != 3 && j != 4 && j != 5 && j != 6) {
                    dp[i] = (dp[i] + dp[i - 1]) % MOD;
                }
                count[j] = (count[j] + 1) % MOD;
            }
        }
        return dp[n];
    }
}
